import torch
import torchvision.transforms as transforms
from torchvision import models
from flask import Flask, request, jsonify
import io
from PIL import Image
import hashlib
import secrets
import os
from functools import wraps
import logging

app = Flask(__name__)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

MAX_IMAGE_SIZE = 10 * 1024 * 1024  # 10MB
ALLOWED_EXTENSIONS = {'jpg', 'jpeg', 'png'}
ALLOWED_MIME_TYPES = {'image/jpeg', 'image/png'}
MAX_IMAGE_DIMENSIONS = (4096, 4096)
MIN_IMAGE_DIMENSIONS = (32, 32)

API_KEYS = set(os.environ.get('API_KEYS', '').split(','))
if not API_KEYS or API_KEYS == {''}:
    raise ValueError("API_KEYS environment variable must be set")

model = models.resnet50(pretrained=True)
model.eval()

with open('imagenet_classes.txt', 'r') as f:
    categories = [s.strip() for s in f.readlines()]

normalize = transforms.Normalize(mean=[0.485, 0.456, 0.406],
                                 std=[0.229, 0.224, 0.225])

preprocess = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    normalize,
])

def require_api_key(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        api_key = request.headers.get('X-API-Key')
        if not api_key or api_key not in API_KEYS:
            logger.warning(f"Unauthorized access attempt from {request.remote_addr}")
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated_function

def validate_image_file(file_data):
    if len(file_data) > MAX_IMAGE_SIZE:
        raise ValueError(f"Image size exceeds maximum allowed size of {MAX_IMAGE_SIZE} bytes")
    
    try:
        img = Image.open(io.BytesIO(file_data))
    except Exception as e:
        raise ValueError("Invalid image file format")
    
    if img.format.lower() not in ['jpeg', 'png']:
        raise ValueError(f"Unsupported image format: {img.format}")
    
    width, height = img.size
    if width > MAX_IMAGE_DIMENSIONS[0] or height > MAX_IMAGE_DIMENSIONS[1]:
        raise ValueError(f"Image dimensions exceed maximum allowed: {MAX_IMAGE_DIMENSIONS}")
    
    if width < MIN_IMAGE_DIMENSIONS[0] or height < MIN_IMAGE_DIMENSIONS[1]:
        raise ValueError(f"Image dimensions below minimum required: {MIN_IMAGE_DIMENSIONS}")
    
    if img.mode not in ['RGB', 'L', 'RGBA']:
        raise ValueError(f"Unsupported image mode: {img.mode}")
    
    return img

def apply_adversarial_defenses(img_tensor):
    noise_level = 0.01
    noise = torch.randn_like(img_tensor) * noise_level
    img_tensor = img_tensor + noise
    
    img_tensor = torch.clamp(img_tensor, 0, 1)
    
    return img_tensor

def detect_adversarial_patterns(img_tensor):
    pixel_variance = torch.var(img_tensor).item()
    if pixel_variance < 0.0001 or pixel_variance > 1.0:
        return True
    
    mean_val = torch.mean(img_tensor).item()
    if mean_val < 0.01 or mean_val > 0.99:
        return True
    
    return False

@app.route('/classify', methods=['POST'])
@require_api_key
def classify_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400
    
    file = request.files['image']
    
    if file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400
    
    content_type = file.content_type
    if content_type not in ALLOWED_MIME_TYPES:
        return jsonify({'error': f'Invalid content type: {content_type}'}), 400
    
    try:
        file_data = file.read()
        
        img = validate_image_file(file_data)
        
        if img.mode == 'RGBA':
            img = img.convert('RGB')
        elif img.mode == 'L':
            img = img.convert('RGB')
        
        img_tensor = preprocess(img)
        
        if detect_adversarial_patterns(img_tensor):
            logger.warning(f"Potential adversarial pattern detected from {request.remote_addr}")
            return jsonify({'error': 'Image rejected due to suspicious patterns'}), 400
        
        img_tensor = apply_adversarial_defenses(img_tensor)
        
        img_tensor = img_tensor.unsqueeze(0)
        
        with torch.no_grad():
            output = model(img_tensor)
        
        probabilities = torch.nn.functional.softmax(output[0], dim=0)
        
        top5_prob, top5_catid = torch.topk(probabilities, 5)
        
        results = []
        for i in range(top5_prob.size(0)):
            category = categories[top5_catid[i]]
            confidence = top5_prob[i].item()
            results.append({
                'class': category,
                'confidence': round(confidence, 4)
            })
        
        logger.info(f"Classification successful from {request.remote_addr}")
        
        return jsonify({
            'predicted_class': results[0]['class'],
            'confidence': results[0]['confidence'],
            'top_5_predictions': results
        }), 200
        
    except ValueError as e:
        logger.warning(f"Validation error from {request.remote_addr}: {str(e)}")
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        logger.error(f"Internal error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

